<div class="section-panel">
    <h4 class="section-heading">Profile</h4>

    @if (_loading)
    {
        <p class="text-muted">Loading profile…</p>
    }
    else if (_error is not null)
    {
        <div class="alert alert-danger">@_error</div>
    }
    else
    {
        <div class="profile-layout">
