{"file_text": "@using sv_9b306a4a34544d14aebc40e3e478fc32.Models
@inject ISettingsService SettingsService

<div class="section-panel">
    <h4 class="section-heading">Security</h4>

    @if (_loading)
    {
        <p class="text-muted">Loading security settings…</p>
    }
    else if (_error is not null)
    {
        <div class="alert alert-danger">@_error</div>
    }
    else
    {
        @* --- Change Password Panel --- *@
        <div class="expandable-panel">
            <button class="panel-toggle" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                <span>Change Password</span>
                <span>@(_passwordPanelOpen ? "▲" : "▼")</span>
            </button>

            @if (_passwordPanelOpen)
            {
                <div class="panel-body">
                    <div class="field-group">
                        <label class="form-label" for="currentPassword">Current Password</label>
                        <input id="currentPassword" type="password" class="form-control" @bind="_currentPassword" />
                    </div>
                    <div class="field-group">
                        <label class="form-label" for="newPassword">New Password</label>
                        <input id="newPassword" type="password" class="form-control" @bind="_newPassword" />
                    </div>
                    <div class="field-group">
                        <label class="form-label" for="confirmPassword">Confirm Password</label>
                        <input id="confirmPassword" type="password" class="form-control" @bind="_confirmPassword" />
                    </div>

                    @if (_passwordError is not null)
                    {
                        <div class="alert alert-danger mt-2">@_passwordError</div>
                    }
                    @if (_passwordSuccess is not null)
                    {
                        <div class="alert alert-success mt-2">@_passwordSuccess</div>
                    }

                    <button class="btn btn-primary mt-2" @onclick="UpdatePasswordAsync" disabled="@_changingPassword">
                        @(_changingPassword ? "Updating…" : "Update Password")
                    </button>
                </div>
            }
        </div>

        @* --- Two-Factor Authentication --- *@
        <div class="tfa-section">
            <div class="tfa-row">
                <div>
                    <strong>Two-Factor Authentication</strong>
                    <span class="status-badge @(_twoFactorEnabled ? "enabled" : "disabled")">
                        @(_twoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                </div>
                <input type="checkbox" class="form-check-input" checked="@_twoFactorEnabled"
                       @onchange="e => _twoFactorEnabled = (bool)(e.Value ?? false)" />
            </div>
            @if (_lastPasswordChange.HasValue)
            {
                <p class="text-muted last-change">Last password change: @_lastPasswordChange.Value.ToString("MMMM dd, yyyy")</p>
            }
        </div>

        @* --- Active Sessions --- *@
        <h5 class="sub-heading">Active Sessions</h5>
        @if (_sessions.Count == 0)
        {
            <p class="text-muted">No active sessions.</p>
        }
        else
        {
            <div class="table-responsive">
                <table class="table table-striped">
                    <thead>
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var session in _sessions)
                        {
                            <tr @key="session.Id">
                                <td>@session.Device</td>
                                <td>@session.Location</td>
                                <td>@session.LastActive.ToString("g")</td>
                                <td>
                                    @if (session != _sessions[0])
                                    {
                                        <button class="btn btn-sm btn-outline-danger"
                                                @onclick="() => PromptRevoke(session)">
                                            Revoke
                                        </button>
                                    }
                                    else
                                    {
                                        <span class="badge bg-success">Current</span>
                                    }
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
            </div>
        }

        @* --- Revoke Confirmation Dialog --- *@
        @if (_sessionToRevoke is not null)
        {
            <div class="confirm-overlay">
                <div class="confirm-dialog">
                    <p>Revoke session on <strong>@_sessionToRevoke.Device</strong> in <strong>@_sessionToRevoke.Location</strong>?</p>
                    <div class="confirm-actions">
                        <button class="btn btn-danger" @onclick="ConfirmRevokeAsync" disabled="@_revoking">
                            @(_revoking ? "Revoking…" : "Yes, Revoke")
                        </button>
                        <button class="btn btn-outline-secondary" @onclick="CancelRevoke" disabled="@_revoking">Cancel</button>
                    </div>
                </div>
            </div>
        }
    }
</div>

@code {
    private bool _loading = true;
    private string? _error;

    // Password panel
    private bool _passwordPanelOpen;
    private bool _changingPassword;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _passwordError;
    private string? _passwordSuccess;

    // 2FA
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;

    // Sessions
    private List<ActiveSession> _sessions = [];
    private ActiveSession? _sessionToRevoke;
    private bool _revoking;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            var settings = await SettingsService.GetSecuritySettingsAsync();
            _twoFactorEnabled = settings.TwoFactorEnabled;
            _lastPasswordChange = settings.LastPasswordChange;
            _sessions = [..settings.Sessions];
        }
        catch (Exception ex)
        {
            _error = $"Failed to load security settings: {ex.Message}";
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task UpdatePasswordAsync()
    {
        _passwordError = null;
        _passwordSuccess = null;

        if (string.IsNullOrWhiteSpace(_newPassword))
        {
            _passwordError = "New password is required.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _passwordError = "Passwords do not match.";
            return;
        }

        _changingPassword = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _passwordSuccess = "Password updated successfully!";
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
        }
        catch (Exception ex)
        {
            _passwordError = $"Failed to change password: {ex.Message}";
        }
        finally
        {
            _changingPassword = false;
        }
    }

    private void PromptRevoke(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null) return;

        _revoking = true;
        try
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _sessions.RemoveAll(s => s.Id == _sessionToRevoke.Id);
            _sessionToRevoke = null;
        }
        catch (Exception ex)
        {
            _error = $"Failed to revoke session: {ex.Message}";
        }
        finally
        {
            _revoking = false;
        }
    }
}
