@using sv_9b306a4a34544d14aebc40e3e478fc32.Models

<nav class="settings-sidebar">
    <h5 class="sidebar-title">Settings</h5>
    <ul class="sidebar-nav">
        @foreach (var section in _sections)
        {
            <li @key="section.Key">
                <button class="sidebar-btn @(ActiveSection == section.Key ? "active" : "")"
                        @onclick="() => OnSectionChanged.InvokeAsync(section.Key)">
                    <span class="sidebar-icon">@section.Icon</span>
                    <span>@section.Label</span>
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter, EditorRequired] public string ActiveSection { get; set; } = "";
    [Parameter] public EventCallback<string> OnSectionChanged { get; set; }

    private readonly record struct SectionDef(string Key, string Label, string Icon);

    private static readonly SectionDef[] _sections =
    [
        new("profile", "Profile", "👤"),
        new("notifications", "Notifications", "🔔"),
        new("security", "Security", "🔒"),
        new("appearance", "Appearance", "🎨"),
    ];
}

@using sv_9b306a4a34544d14aebc40e3e478fc32.Models
@inject ISettingsService SettingsService

<div class="section-panel">
    <h4 class="section-heading">Profile</h4>

    @if (_loading)
    {
        <p class="text-muted">Loading profile…</p>
    }
    else if (_error is not null)
    {
        <div class="alert alert-danger">@_error</div>
    }
    else
    {
        <div class="profile-layout">
            <div class="avatar-area">
                <div class="avatar-preview">
                    @if (!string.IsNullOrWhiteSpace(_avatarUrl))
                    {
                        <img src="@_avatarUrl" alt="Avatar" class="avatar-img" />
                    }
                    else
                    {
                        <span class="avatar-placeholder">👤</span>
                    }
                </div>
                <span class="avatar-url-label text-muted">@_avatarUrl</span>
            </div>

            <div class="form-fields">
                <div class="field-group">
                    <label class="form-label" for="displayName">Display Name</label>
                    <input id="displayName" class="form-control" @bind="_displayName" />
                </div>
                <div class="field-group">
                    <label class="form-label" for="email">Email</label>
                    <input id="email" type="email" class="form-control" @bind="_email" />
                </div>
                <div class="field-group">
                    <label class="form-label" for="bio">Bio</label>
                    <textarea id="bio" class="form-control" rows="4" @bind="_bio"></textarea>
                </div>
            </div>
        </div>

        @if (_successMessage is not null)
        {
            <div class="alert alert-success mt-3">@_successMessage</div>
        }

        <div class="button-row">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @(_saving ? "Saving…" : "Save Changes")
            </button>
            <button class="btn btn-outline-secondary" @onclick="Discard">Discard Changes</button>
        </div>
    }
</div>

@code {
    private bool _loading = true;
    private bool _saving;
    private string? _error;
    private string? _successMessage;

    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";

    private UserProfile? _savedProfile;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            _savedProfile = await SettingsService.GetProfileAsync();
            ApplyProfile(_savedProfile);
        }
        catch (Exception ex)
        {
            _error = $"Failed to load profile: {ex.Message}";
        }
        finally
        {
            _loading = false;
        }
    }

    private void ApplyProfile(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _avatarUrl = profile.AvatarUrl;
        _bio = profile.Bio;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _successMessage = null;
        try
        {
            var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await SettingsService.SaveProfileAsync(updated);
            _savedProfile = updated;
            _successMessage = "Profile saved successfully!";
        }
        catch (Exception ex)
        {
            _error = $"Save failed: {ex.Message}";
        }
        finally
        {
            _saving = false;
        }
    }

    private void Discard()
    {
        _successMessage = null;
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
        }
    }
}

