toolArgs.file_text:
@using sv_9b306a4a34544d14aebc40e3e478fc32.Models
@inject ISettingsService SettingsService

<div class="section-panel">
    <h4 class="section-heading">Notifications</h4>

    @if (_loading)
    {
        <p class="text-muted">Loading preferences…</p>
    }
    else if (_error is not null)
    {
        <div class="alert alert-danger">@_error</div>
    }
    else
    {
        <div class="toggle-group">
            <label class="toggle-row">
                <span>Email Notifications</span>
                <input type="checkbox" class="form-check-input" @bind="_emailNotifications" />
            </label>
            <label class="toggle-row">
                <span>Push Notifications</span>
                <input type="checkbox" class="form-check-input" @bind="_pushNotifications" />
            </label>
            <label class="toggle-row">
                <span>Weekly Digest</span>
                <input type="checkbox" class="form-check-input" @bind="_weeklyDigest" />
            </label>
        </div>

        <h5 class="sub-heading">Muted Channels</h5>
        @if (_allChannels.Count == 0)
        {
            <p class="text-muted">No channels available.</p>
        }
        else
        {
            <ul class="channel-list">
                @foreach (var channel in _allChannels)
                {
                    <li @key="channel" class="channel-item">
                        <label>
                            <input type="checkbox"
                                   class="form-check-input"
                                   checked="@_mutedChannels.Contains(channel)"
                                   @onchange="() => ToggleMute(channel)" />
                            <span>@channel</span>
                        </label>
                    </li>
                }
            </ul>
        }

        @if (_successMessage is not null)
        {
            <div class="alert alert-success mt-3">@_successMessage</div>
        }

        <div class="button-row">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @(_saving ? "Saving…" : "Save Preferences")
            </button>
        </div>
    }
</div>

@code {
    private bool _loading = true;
    private bool _saving;
    private string? _error;
    private string? _successMessage;

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<string> _mutedChannels = [];
    private List<string> _allChannels = [];

    protected override async Task OnInitializedAsync()
    {
        try
        {
            var prefs = await SettingsService.GetNotificationPrefsAsync();
            _emailNotifications = prefs.EmailNotifications;
            _pushNotifications = prefs.PushNotifications;
            _weeklyDigest = prefs.WeeklyDigest;
            _mutedChannels = [..prefs.MutedChannels];
            // Seed channel list — in production this would come from an API
            _allChannels = ["general", "announcements", "engineering", "design", "marketing", "random"];
        }
        catch (Exception ex)
        {
            _error = $"Failed to load preferences: {ex.Message}";
        }
        finally
        {
            _loading = false;
        }
    }

    private void ToggleMute(string channel)
    {
        if (!_mutedChannels.Remove(channel))
        {
            _mutedChannels.Add(channel);
        }
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _successMessage = null;
        try
        {
            var prefs = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, [.._mutedChannels]);
            await SettingsService.SaveNotificationPrefsAsync(prefs);
            _successMessage = "Preferences saved!";
        }
        catch (Exception ex)
        {
            _error = $"Save failed: {ex.Message}";
        }
        finally
        {
            _saving = false;
        }
    }
}

