toolArgs.file_text:
.section-panel {
    padding: 1.5rem;
}

.section-heading {
    margin: 0 0 1.25rem;
    font-weight: 600;
}

.expandable-panel {
    border: 1px solid #dee2e6;
    border-radius: 0.375rem;
    margin-bottom: 1.5rem;
    overflow: hidden;
}

.panel-toggle {
    display: flex;
    justify-content: space-between;
    align-items: center;
    width: 100%;
    padding: 0.75rem 1rem;
    border: none;
    background: #f8f9fa;
    font-weight: 500;
    font-size: 0.95rem;
    cursor: pointer;
}

.panel-toggle:hover {
    background: #e9ecef;
}

.panel-body {
    padding: 1rem;
    display: flex;
    flex-direction: column;
    gap: 0.75rem;
}

.field-group {
    display: flex;
    flex-direction: column;
    gap: 0.25rem;
}

.tfa-section {
    margin-bottom: 1.5rem;
}

.tfa-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.75rem;
    background: #f8f9fa;
    border-radius: 0.375rem;
}

.status-badge {
    display: inline-block;
    padding: 0.15rem 0.5rem;
    border-radius: 1rem;
    font-size: 0.75rem;
    font-weight: 600;
    margin-left: 0.5rem;
}

.status-badge.enabled {
