toolArgs.file_text:
@using sv_9b306a4a34544d14aebc40e3e478fc32.Models
@inject ISettingsService SettingsService

<div class="section-panel">
    <h4 class="section-heading">Appearance</h4>

    @if (_loading)
    {
        <p class="text-muted">Loading appearance settings…</p>
    }
    else if (_error is not null)
    {
        <div class="alert alert-danger">@_error</div>
    }
    else
    {
        <div class="settings-grid">
            @* Theme *@
            <fieldset class="option-group">
                <legend>Theme</legend>
                <div class="radio-options">
                    @foreach (var theme in _themes)
                    {
                        <label @key="theme" class="radio-label">
                            <input type="radio" name="theme" value="@theme"
                                   checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            <span>@theme</span>
                        </label>
                    }
                </div>
            </fieldset>

            @* Font Size *@
            <fieldset class="option-group">
                <legend>Font Size</legend>
                <div class="radio-options">
                    @foreach (var size in _fontSizes)
                    {
                        <label @key="size" class="radio-label">
                            <input type="radio" name="fontSize" value="@size"
                                   checked="@(_fontSize == size)"
                                   @onchange="() => _fontSize = size" />
                            <span>@size</span>
                        </label>
                    }
                </div>
            </fieldset>

            @* Language *@
            <div class="option-group">
                <label class="form-label" for="language">Language</label>
                <select id="language" class="form-select" @bind="_language">
                    @foreach (var lang in _languages)
                    {
                        <option @key="lang.Key" value="@lang.Key">@lang.Value</option>
                    }
                </select>
            </div>

            @* Compact Mode *@
            <div class="option-group">
                <label class="toggle-row">
                    <span>Compact Mode</span>
                    <input type="checkbox" class="form-check-input" @bind="_compactMode" />
                </label>
            </div>
        </div>

        @* Live Preview *@
        <div class="preview-area @GetPreviewClasses()">
            <h6 class="preview-title">Preview</h6>
            <p class="preview-text">This is how your content will look with the selected settings.</p>
            <div class="preview-card">
                <strong>Sample Card</strong>
                <p>Dashboard item preview with your appearance choices applied.</p>
                <button class="btn btn-sm btn-primary">Action</button>
            </div>
        </div>

        @if (_successMessage is not null)
        {
            <div class="alert alert-success mt-3">@_successMessage</div>
        }

        <div class="button-row">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @(_saving ? "Saving…" : "Save")
            </button>
        </div>
    }
</div>

@code {
    private bool _loading = true;
    private bool _saving;
    private string? _error;
    private string? _successMessage;

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "en";
    private bool _compactMode;

    private static readonly string[] _themes = ["Light", "Dark", "System"];
    private static readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private static readonly Dictionary<string, string> _languages = new()
    {
        ["en"] = "English",
        ["es"] = "Español",
        ["fr"] = "Français",
        ["de"] = "Deutsch",
        ["ja"] = "日本語",
    };

    protected override async Task OnInitializedAsync()
    {
        try
        {
            var settings = await SettingsService.GetAppearanceAsync();
            _theme = settings.Theme;
            _fontSize = settings.FontSize;
            _language = settings.Language;
            _compactMode = settings.CompactMode;
        }
        catch (Exception ex)
        {
            _error = $"Failed to load appearance settings: {ex.Message}";
        }
        finally
        {
            _loading = false;
        }
    }

    private string GetPreviewClasses()
    {
        var theme = _theme.ToLowerInvariant();
        var size = _fontSize.ToLowerInvariant();
        var compact = _compactMode ? "compact" : "";
        return $"theme-{theme} size-{size} {compact}".Trim();
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _successMessage = null;
        try
        {
            var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
            await SettingsService.SaveAppearanceAsync(settings);
            _successMessage = "Appearance settings saved!";
        }
        catch (Exception ex)
        {
            _error = $"Save failed: {ex.Message}";
        }
        finally
        {
            _saving = false;
        }
    }
}

