}

.section-heading {
    margin: 0 0 1.25rem;
    font-weight: 600;
}

.settings-grid {
    display: flex;
    flex-direction: column;
    gap: 1.25rem;
    margin-bottom: 1.5rem;
}

.option-group {
    border: none;
    padding: 0;
    margin: 0;
}

.option-group legend {
    font-size: 0.95rem;
    font-weight: 600;
    margin-bottom: 0.5rem;
}

.radio-options {
    display: flex;
    gap: 1.25rem;
}

.radio-label {
    display: flex;
    align-items: center;
    gap: 0.375rem;
    cursor: pointer;
}

.toggle-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.5rem 0.75rem;
    background: #f8f9fa;
    border-radius: 0.375rem;
    cursor: pointer;
}

/* Live Preview */
.preview-area {
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    padding: 1.25rem;
    margin-bottom: 1rem;
    transition: all 0.2s;
}

.preview-title {
    margin: 0 0 0.5rem;
    font-weight: 600;
}

.preview-text {
    margin: 0 0 0.75rem;
}

.preview-card {
    border: 1px solid #dee2e6;
    border-radius: 0.375rem;
    padding: 0.75rem;
}

.preview-card p {
    margin: 0.375rem 0;
}

/* Theme variants */
.theme-light {
    background: #fff;
    color: #212529;
}

.theme-dark {
    background: #212529;
    color: #f8f9fa;
    border-color: #495057;
}

.theme-dark .preview-card {
    border-color: #495057;
}

.theme-system {
    background: #f0f0f0;
    color: #333;
}

/* Font size variants */
.size-small {
    font-size: 0.8rem;
}

.size-medium {
    font-size: 1rem;
}

.size-large {
    font-size: 1.2rem;
}

/* Compact mode */
.compact {
    padding: 0.625rem;
    line-height: 1.3;
}

.compact .preview-card {
    padding: 0.375rem;
}

.button-row {
    display: flex;
    gap: 0.75rem;
    margin-top: 1.25rem;
}

