arguments.file_text:
@page "/settings"
@using sv_9b306a4a34544d14aebc40e3e478fc32.Components.Settings
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <SettingsSidebar ActiveSection="@_activeSection" OnSectionChanged="section => _activeSection = section" />

    <div class="settings-content">
        @switch (_activeSection)
        {
            case "profile":
                <ProfileSection />
                break;
            case "notifications":
                <NotificationsSection />
                break;
            case "security":
                <SecuritySection />
                break;
            case "appearance":
                <AppearanceSection />
                break;
        }
    </div>
</div>

@code {
    private string _activeSection = "profile";
}

.settings-dashboard {
    display: flex;
    min-height: calc(100vh - 100px);
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    overflow: hidden;
    background: #fff;
}

.settings-content {
    flex: 1;
    overflow-y: auto;
}

